var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"뭐냐! 저 공세는 대체 뭐냔 말이다!","JPN":"何なんだ！　あの猛烈な勢いは何なのだ！","ENG":"What? Why are they mounting an offensive like that?","TWN":"搞什麼！這個攻勢是怎麼回事！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"곧 침식체로 변할 폐품들 주제에 왜 겁도 없이 달려드는 거지?!","JPN":"もうじき侵食体に変異するだろう廃棄品どものくせに、\\n何故こうも果敢に襲いかかってくるのだ！？","ENG":"They're nothing but scraps doomed to become C.O.s soon. Where did they find the gall to come attacking?","TWN":"他們明明馬上就要變成侵蝕體了，難道他們都不害怕的嗎？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"어차피 침식되어 가는 몸인데 뭐가 두렵겠나, 도플갱어!","JPN":"どうせ侵食しかかってる身体だ。\\n今更怖いものなんてあるもんかよ、ドッペルゲンガーめ！","ENG":"What have we got to fear when we're all good as dead, Doppelganger?","TWN":"反正都要變成侵蝕體了，還有什麼好害的，二重身！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_TOUCH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"오히려 다쳐도 아프지 않으니 잘됐군!","JPN":"怪我をしても痛くねえし、むしろ便利になったもんだぜ！","ENG":"If anything, the Corruption has numbed our pain! It's the perfect time for fighting!","TWN":"受傷也感覺不到痛，這反倒是件好事！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"이봐, 발레리. 혹시 내가 침식체가 돼서 정신줄 놓으면 민폐 끼치기 전에 알아서 끝내 달라고.","JPN":"おい、ヴァレリー。もし俺が侵食体になって頭がイカれちまったら、\\nみんなに迷惑かける前にお前が終わらせてくれよな。","ENG":"Hey, Valeriy. If I start losing my mind as a C.O., put me out of my misery before I do anything stupid.","TWN":"喂，瓦萊里，萬一我變成侵蝕體失去自我的話，在我造成其他人的麻煩前，你一定要馬上殺了我。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"내가 할 소리야, 예고르. 가능하면 깔끔하게 부탁하지.","JPN":"俺からも頼むぜ、イェゴール。なるべくサクッと逝かせてくれ。","ENG":"Likewise, Yegor. Try to make it as clean and quick as possible.","TWN":"這是我要說的話，伊高爾，請你乾脆地了結我。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"다들 조용. 찬물도 위아래가 있다는 거 잊었어?","JPN":"まあ、生意気ですこと。上官を差し置いて先に逝こうっていうの？","ENG":"Tut, tut, everyone. Don't you forget that I outrank y'all.","TWN":"全都安靜，你們是不知道長幼有序嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"나보다 먼저 침식체가 되는 애는 가만 안 둬. 알겠지?","JPN":"私より先に侵食体になるような子は、ただでは済まないからね。\\n以後気をつけなさい！","ENG":"None of you better beat me to becoming a C.O. Alright?","TWN":"我不會放過那些比我先變成侵蝕體的傢伙，知道了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"지독한 것들......! 죽기 전에 마지막 발악이라도 할 셈인가......!","JPN":"忌々しい奴らめ……！　最期の悪足掻きのつもりか……！","ENG":"You relentless fools! So you want to throw one last tantrum before you die?","TWN":"該死的東西……！都要死了，還要做最後的掙扎嗎……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"......그러길래 내가 싸우지 말고 기다리자고 했잖아.","JPN":"……だから戦わないで待とうって言ったのに。","ENG":"I told you we should've waited instead of fighting.","TWN":"……所以我才說過不要正面交鋒，而是要靜靜等待啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"알렉스, 내 앞에서 또 그딴 소리를 해?","JPN":"アレックス、貴様はまだそんなことが言えるのか？","ENG":"You dare bring that up to me again, Alex?","TWN":"雅蕾克絲，妳又在我面前說這些嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"무능한 네놈들이 포격만 제대로 맞췄어도 이럴 일은 없었어!","JPN":"無能な貴様たちが砲撃さえ外していなければ、こんなザマにはなっていない！","ENG":"If only you incompetent fools had landed your shots, it wouldn't have come to this!","TWN":"如果不是妳這個無能的笨蛋打歪，根本不會發生這種事！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"하는 수 없지. <color=#ffd34c>그걸</color> 동원해.","JPN":"仕方ない。<color=#ffd34c>あれ</color>を出すぞ。","ENG":"This leaves us no choice. Get <color=#ffd34c>it</color> ready.","TWN":"沒辦法了。用<color=#ffd34c>那個</color>吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"놈들과 방주를 싸잡아 박살내 주지!","JPN":"奴らと箱舟をまとめて潰してやる！","ENG":"We'll crush them and the Ark together!","TWN":"我要把他們連同方舟一起粉碎！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"크로노스를?","JPN":"クロノスを使うの？","ENG":"You mean Chronos?","TWN":"妳是說克羅諾斯？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"무리야. 그 녀석을 움직이려고 애들 수십 명을 동력원으로 썼는데도 꿈쩍 안 했잖아.","JPN":"無理よ。あいつを動かそうと子どもたちを何十人も\\n動力源として放り込んだのに、びくともしなかったじゃない。","ENG":"I'm not sure we can. We burnt up dozens of our guys to power that thing, but it wouldn't budge.","TWN":"不行，為了啟動那東西，我們曾把數十個孩子當作動力源去驅動，但最後還是失敗了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그럼 더 질 좋은 동력원을 쓰면 되겠군.","JPN":"なら、より質の高い動力源を用いるまでだ。","ENG":"Then we'll just have to find a better source of fuel.","TWN":"那就用更優質的動力源就好了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"지난번 실패에 대해 누군가 책임을 져야 하지 않겠나, 알렉스?","JPN":"前回の失敗の責任は誰かに取ってもらわねばならん。\\nそうではないか？　アレックス。","ENG":"After all, someone's got to be held accountable about the last failure. Don't you think so, Alex?","TWN":"關於上次的失敗，我想有人得負起責任才行，是吧，雅蕾克絲？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"널 동력원으로 쓴다고 해도 거부하진 않겠지?","JPN":"貴様を動力源に使っても文句はないな？","ENG":"I'm sure you wouldn't mind if we used you as the fuel, would you?","TWN":"我要把妳用作動力源，妳應該不會拒絕吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"병사들! 부관을 구속해라!","JPN":"兵たちよ！　副官を拘束せよ！","ENG":"Troops! Apprehend my adjutant!","TWN":"士兵們！把副官抓起來！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"뭣들 하는 거냐! 어서 붙잡지 않고!","JPN":"何をしている！　さっさと捕らえろ！","ENG":"What are you waiting for! Grab her, at once!","TWN":"你們在幹什麼！快抓住她啊！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"꾸물대는 놈들은 내 손으로......!","JPN":"グズグズする奴は私が直々に……！","ENG":"Anyone who hesitates will have to answer to my—","TWN":"誰敢拖拖拉拉的，我就親自……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"커헉......!","JPN":"ガハッ……！","ENG":"Ack!","TWN":"唔……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG_02"},{"id":"L38_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"알렉, 스......! 너......! 날 찌르다니......!","JPN":"アレック、ス……！　貴様……ッ！　私を刺したな……！","ENG":"Alex! You... You stabbed me!","TWN":"雅蕾，克絲……！妳……！妳竟敢……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"내가 머리에 총 맞았니? 그동안 억지 부려도 고분고분 받아 주니까 눈에 뵈는 게 없지?","JPN":"私は至って正気よ。今までワガママに付き合ってあげたけど\\nどうも甘やかしすぎだったみたい。","ENG":"You think I took a bullet to the head? You think you could do as you please just because I put up with all your crap, huh?","TWN":"妳當我腦袋壞了嗎？一直以來，我都在迎合妳蠻不講理的行為，所以妳就自以為了不起了？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_SMASH_ATTACK_SMALL"},{"id":"L41_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"애들이 바라는 건 방주 안에 들어 있는 원본을 잡아먹는 거야.","JPN":"子どもたち全員の望みは箱舟の中のオリジナルを喰うことだわ。","ENG":"The only thing the kids want is to devour their originals in the Ark.","TWN":"孩子們想要的，是吃掉方舟裡的本體。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"네가 지껄이던 같잖은 승리 따위가 아니라.","JPN":"アンタが拘っていたくだらない勝利なんか\\n誰も望んじゃいないってわけ。","ENG":"They couldn't care less about your ridiculous idea of victory.","TWN":"而不是妳那冠冕堂皇的勝利。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"이...... 배신자......!","JPN":"この……裏切者が……！","ENG":"You... Traitor!","TWN":"妳這……叛徒……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"난 원본처럼 모자란 애까지 챙겨 줄 만큼 마음이 넓진 않거든.","JPN":"私はオリジナルと違って、\\n遅れてる子どもの世話を焼くほど心が広くないのよね。","ENG":"Unlike my original, I don't have the patience to look after someone as thick as you.","TWN":"我可不像本體一樣，會善良到去照顧像妳這種沒用的東西。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그러게 얌전히 있었어야지. 바퀴벌레랑 싸우느라 가진 힘도 잔뜩 써 버린 주제에.","JPN":"言うことを聞いて大人しくしてれば良かったじゃない。\\nゴキブリと戦って、力もかなり消耗しちゃったんでしょう？","ENG":"You should've played nice. Especially since you've depleted yourself fighting the Roach.","TWN":"所以妳應該安分點，妳和蟑螂戰鬥的時候，不是早就耗盡力量了嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"난 내 원본이랑 달라서 말이야.","JPN":"もう一度言ってあげるわ。私はオリジナルとは違うの。","ENG":"I'm not like my original, you see.","TWN":"我和我的本體不一樣。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"너처럼 멍청하고 말귀 못 알아듣는 멍청이까지 챙겨 줄 만큼 아량이 넓진 않아.","JPN":"アンタのように聞き分けのないおバカさんの世話を焼くほど\\n寛大じゃないの。","ENG":"I'm not gracious enough to put up with a stubborn idiot like you.","TWN":"我沒有寬大到會去照顧你這種聽不懂人話的笨蛋。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"뭐, 네 남은 힘은 우리가 유용하게 써 줄게.","JPN":"まあ、残っているアンタの力は私たちが有効活用するつもりだけどね。","ENG":"But we'll make great use of whatever energy you've got left.","TWN":"不過，我們會好好使用妳剩下的力量的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"네 말대로 우린 침식체잖아? 필요하면 같은 침식체도 잡아먹는.","JPN":"アンタの言ったとおり、私たちは侵食体でしょ？\\n必要なら共喰いだって平気でするわ。","ENG":"After all, we're all just C.O.s, as you said. C.O.s don't hesitate to eat each other when necessary.","TWN":"就跟妳說得一樣，我們是侵蝕體啊？如有必要的話，連同類侵蝕體都會吞噬。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"죽여......! 죽여 버리겠...... 어......! 네놈들 전부......!","JPN":"殺す……！　殺して……やる……！　貴様たち全員……！","ENG":"I'll... I'll... kill you... All of you!","TWN":"殺……！殺了……妳們！把你們全都……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"얘들아. 사격 개시.","JPN":"みんな、射撃開始よ。","ENG":"Alright, guys. Open fire.","TWN":"各位，開始射擊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIFLE_ADMIN_CORRUPT_MAZE","text":{"KOREA":"드디어 홀가분해졌군요. 힘만 센 멍청이 비위 맞춰 주느라 고생 깨나 했습니다.","JPN":"ようやくスッキリできましたね。この腕力バカの機嫌を取るのは\\nさぞやお疲れだったでしょう。","ENG":"Dang, that felt good. It was such a pain in the butt trying to humor that brutish idiot.","TWN":"終於清靜多了。為了討好一個只會打架的笨蛋，還真是費了不少力氣呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RIFLE_ADMIN_CORRUPT_MAZE","text":{"KOREA":"이제 어떡할까요?","JPN":"さて、これからどうしましょう？","ENG":"So what now?","TWN":"接下來要怎麼做？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"뭐...... 시간 끌기는 글렀네.","JPN":"まあ……もう時間稼ぎも無理そうだしね。","ENG":"Well... I guess buying more time's not an option anymore.","TWN":"嗯……要爭取時間看來是不可能了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIFLE_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"하는 수 없지. 이 녀석을 크로노스에 처넣어.","JPN":"仕方ないわ。こいつをクロノスにぶち込んじゃって。","ENG":"I guess we have no choice. Shove her into the Chronos.","TWN":"沒辦法，把這傢伙丟進克羅諾斯裡吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"차라리 잘됐지, 뭐.","JPN":"むしろ好都合よ。","ENG":"It’s all for the best, I guess.","TWN":"這反倒是件好事。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"원본들이 직접 여기까지 와 줘서 찾으러 갈 수고는 덜었잖아?","JPN":"オリジナルがここまで出向いてくれて、探しに行く手間が省けたわ。","ENG":"At least we won't have to go looking for our originals since they're already here, right?","TWN":"本體們自己找上門來了，省得我們還要去找他們。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그러니 맛있게 요리해서 잡아먹자.","JPN":"美味しく料理して食べちゃいましょう。","ENG":"So let's cook them up real nice and feast.","TWN":"我們只需好好享用他們就行了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"알았지, 얘들아?","JPN":"みんな、いいわね？","ENG":"Alright, kids?","TWN":"沒問題吧，各位？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_CORRUPT_MAZE","face":"UNIT_IDLE"}}}}]`);export{e as default};